// Extraer respuesta de Gemini
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '¡Hola! Soy el asistente de Kyros. ¿En qué puedo ayudarte hoy?';

// Intentar parsear JSON de la respuesta
let parsed;
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : { respuesta: text };
} catch (e) {
  parsed = { respuesta: text };
}

return [{
  json: {
    ...$input.first().json,
    aiResponse: parsed,
    rawResponse: text
  }
}];

// Preparar respuesta según plataforma
const input = $input.first().json;
const message = input.aiResponse?.respuesta || input.aiResponse || '¡Bienvenido a Kyros Barber! 🪒\n\nSoy tu asistente virtual y puedo ayudarte a agendar tu cita. ¿Te gustaría ver nuestros servicios?';

let output;
if (input.platform === 'telegram') {
  output = {
    chat_id: input.chatId,
    text: message,
    parse_mode: 'Markdown'
  };
} else {
  output = {
    To: input.chatId,
    Body: message
  };
}

return [{ json: { output, platform: input.platform, chatId: input.chatId, sessionId: input.sessionId } }];
